    ('alice@example.com', 'Alice Example', 'us'),
    ('bob@example.com',   'Bob Example',   'mx');

INSERT INTO orders (customer_id, status, subtotal_cents, tax_cents) VALUES
    (1, 'paid',    12500, 1000),
    (2, 'pending',  9900,    0);

INSERT INTO shipments (order_id, carrier, shipped_at) VALUES
    (1, 'DHL', now());

INSERT INTO bookings (room_id, during) VALUES
    (7, int8range(100, 200));

